var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"으윽!","JPN":"ううっ！","ENG":"Agh!","TWN":"唔呃！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"다시 덤벼보겠소?","JPN":"まだ戦いますか？","ENG":"Care to try again?","TWN":"再來嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"항복…! 제가 졌습니다!","JPN":"降参……！　私の負けです！","ENG":"I surrender...! I admit my defeat!","TWN":"投降…！我認輸！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"섭리음양의 법칙에 따라, 그대가 가진 간장의 검조각은 본인이 가져가리다.","JPN":"燮理陰陽のルールに従い、貴殿が所持している干将の剣の欠片は自分が頂いていきましょう。","ENG":"Following the laws of the balance of yin and yang, I shall take your shard of Kanshou.","TWN":"按照燮理陰陽的規定，在下會拿走你身上的干將碎片。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"끙… 그렇게 하시죠.","JPN":"うう……そうなさってください。","ENG":"Errgh... Here, take it.","TWN":"唔…你拿去吧。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"방금 전의 기습은 실례했습니다.","JPN":"突然の奇襲、失礼いたしました。","ENG":"Please excuse my ambush from earlier.","TWN":"剛才失禮了，突然攻擊你。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"괜찮소. 수단과 방법을 가리지 않고 승패를 가리는 것이 섭리음양의 법칙이니 말이오.","JPN":"気にしておりません。手段を選ばず、勝敗を決めることが燮理陰陽のルールですから。","ENG":"No need. The laws of the balance of yin and yang allow the use of any and all methods for victory.","TWN":"沒關係，燮理陰陽的規定是只問輸贏，不問手段。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"일주일만에 백서의 후보들을 일곱이나 꺾었다고 하던데, 확실히 대단한 실력이군요.","JPN":"一週間で白西の候補者を7人も打ち破ったと聞きましたが、確かに素晴らしい実力です。","ENG":"I heard you defeated seven of our candidates within a week. You are certainly skilled.","TWN":"聽說你在短短一週內，就與七名白西的候選人交手過，能力確實不在話下。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"소문이 참 빠르구려.","JPN":"噂というものは早いですね。","ENG":"Rumors travel fast, I see.","TWN":"消息傳得很快呢。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"간부를 제외하면 점조직으로 움직이는 흑동과 달리, 저희 백서 사람들은 필요한 정보를 서로 공유하기도 하니까요.","JPN":"個々で動く黒東とは違って、幹部を除き、我々白西は必要な情報を共有したりしますからね。","ENG":"Unlike Black East, where members act in small groups with the exception of the core members, White West members share vital information with one another.","TWN":"因為我們白西與黑東不同，黑東只有幹部之間才會緊密聯繫，但白西是會彼此分享重要資訊。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그렇다면 다른 백서의 실력자가 있는 곳을 아시오?","JPN":"それなら、他の白西の実力者がいる場所をご存じですか？","ENG":"Then, perhaps you know where I can find a formidable opponent of White West?","TWN":"那你知道其他白西挑戰者所在的位置嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이곳 일대는 더이상 새로운 도전자가 좀처럼 찾아오지 않는구려.","JPN":"この一帯には新しい挑戦者が訪ねてこないのです。","ENG":"It seems that this area has run out of new challengers.","TWN":"這附近似乎已經沒有新的挑戰者。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"흑동의 문주를 노리는 백서의 도전자는 어디에나 있을 겁니다. 당신을 꺾는 것만으로 문파의 모든 것을 얻는 셈이니까요.","JPN":"黒東の門主を狙う白西の挑戦者はどこにでもいるでしょう。あなたに勝つだけで、門派のすべてを得るのと同じなのですから。","ENG":"White West challengers will always swarm around you because defeating you means gaining everything the sect has.","TWN":"\\n覬覦黑東幫主的白西挑戰者應該無所不在，畢竟打敗你就表示可以得到整個門派。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"하지만… 당신의 실력에 버금갈 만한 자는 역시 백서의 으뜸 제자들 정도겠죠.","JPN":"ですが……あなたの実力に匹敵する者でしたら、やはり白西の一番弟子ですかね。","ENG":"However... someone with skills comparable to yours will only be one of White West's best disciples.","TWN":"不過…能與你實力相當的人，應該也是白西門派中一等一的高手。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그들이 어디에 있는지 알고 있소?","JPN":"彼らがどこにいるか、ご存じでしょうか？","ENG":"Do you know where they could be?","TWN":"你知道他們在哪裡嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"전부는 아니지만, 한 명은 알고 있습니다.","JPN":"全員ではないですが、一人なら知っています。","ENG":"Not all of them, but I do know where one is.","TWN":"我只知道其中一個，其他我不清楚。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MEMBER_CLAN_WHITE_NULL","text":{"KOREA":"저 같은 사람과 다르게… 그분께서 도전을 원할지는 저도 확신하기 어렵지만요.","JPN":"私のような者とは違って……あの方が挑戦を望んでいるかはわかりませんが。","ENG":"But unlike me... she might not even want to challenge you to battle.","TWN":"但她和我不一樣，我不確定她是否願意接受挑戰。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"subtitle","speaker":null,"text":{"KOREA":"한 달 뒤.","JPN":"一ヵ月後。","ENG":"One month later.","TWN":"<color=#ffd34c>G1郊區</color>- 保護管轄區"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>그라운드 원 외곽지대</color>- 보호관할 경계구역.","JPN":"<color=#ffd34c>グラウンド・ワンの外郭地帯</color> - 保護管轄警戒区域。","ENG":"<color=#ffd34c>Ground One outer region</color>- Security Zone Border","TWN":"<color=#ffd34c>G1郊區</color>- 保護管轄區"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"어이, 일어나.","JPN":"おい、起きろ。","ENG":"Hey, wake up.","TWN":"喂，起來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"일어나라고. 안 들려?","JPN":"起きろって。聞こえんのか？","ENG":"Wake up. Can't you hear me?","TWN":"我叫你起來沒聽到嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"으음…","JPN":"うむ……","ENG":"Mm...","TWN":"呃嗯…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"오, 깨어났군.","JPN":"やっと目が覚めたか。","ENG":"Hey, you're finally up.","TWN":"喂，你醒啦。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"큭큭, 길바닥에 쓰러져 있던 것 치곤 별로 취한 것 같진 않은데.","JPN":"ククッ、道端に倒れていたが酔いつぶれていたわけじゃないようだな。","ENG":"Heh, she doesn't look that drunk enough to be sleeping on the streets.","TWN":"呵呵，雖然她倒在路邊，但好像不是因為喝醉。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대들이 날 창고로 데려온 거요?","JPN":"貴殿らが自分をここまで連れてきたのですか？","ENG":"Are you the ones who brought me to this warehouse?","TWN":"是你們把在下帶到倉庫的嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"그래, 형님이 귀한 손님이 오신다고 해서 마중을 나갔다가 발견했지.","JPN":"ああ、兄貴から重要な客人が来ると聞いて、出迎えに行く途中で倒れているのを発見したんだ。","ENG":"Yeah. Boss told us to greet an important guest and we found you.","TWN":"正是，老大說有客人來，我出去迎接時正好發現你。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"큭큭, 그런 차가운 바닥에서 자고 있으면 입 돌아간다고. 아가씨.","JPN":"ククッ、そんな冷たい床の上で寝てると凍え死ぬぞ、お嬢さん。","ENG":"Heh. You're gonna get a cold if you sleep out on the streets like that, missy.","TWN":"呵呵，躺在冷冰冰的地板上睡覺會冷死的，小姑娘。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"신세를 졌군. 낮에 깨어 있는 건 좀처럼 익숙지 않아서 말이오.","JPN":"お世話になりました。昼間に起きているのは慣れていないのです。","ENG":"Thank you. I am not used to being awake during the day.","TWN":"謝謝關心，但在下不習慣白天醒著。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그런데, 이 도시엔 손님을 기둥에 묶어 두는 풍습이라도 있는 게요?","JPN":"ところで、この都市ではお客を柱に縛っておく風習でもあるのですか？","ENG":"Then again, does this city have a culture of tying guests to pillars?","TWN":"不過，這裡的習俗是將客人綁在柱子上嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"형님의 지시다. 널 절대로 움직이지 못하게 하라고 하셨거든.","JPN":"兄貴の指示だ。絶対お前を動けないようにしておけって言われたんだよ。","ENG":"Boss's orders. He told us to tie you up good.","TWN":"是老大吩咐的，他說一定要把你綁得死死的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"큭큭, 너무 걱정 말라고. 배고프면 밥은 우리가 떠먹여줄 테니까.","JPN":"ククッ、あんま心配すんな。腹が空いたら飯は食べさせてやるからさ。","ENG":"Heh, don't worry. We'll feed ya ourselves if you ever get hungry.","TWN":"呵呵，沒事的，肚子餓的話我們會餵你吃飯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"배려는 고맙소만, 본인은 갈 길이 바쁘다오.","JPN":"ご配慮はありがたいのですが、自分は忙しいのです。","ENG":"I appreciate your consideration. However, I have someplace to go.","TWN":"謝謝你們的照顧，但在下還有事要忙。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대들의 형님에겐 딱히 볼일도 없다네.","JPN":"貴殿らの兄貴には大した用もありませんし。","ENG":"I have no business with your boss, whoever that may be.","TWN":"而且在下跟你們老大也無冤無仇的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"형님에게 밉보여서 여기까지 온 사람들은 모두 비슷한 얘길하지.","JPN":"兄貴に目を付けられてここまで連れてこられたやつらは、みんな同じようなことを言うんだよな。","ENG":"That's what everyone who crosses him says every time they end up here.","TWN":"你這話我們聽多啦，得罪老大還想跑？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"큭큭, 정말 안 됐구만. 우리 형님은 아주 무자비한 사람이라고.","JPN":"ククッ、本当に残念だな。兄貴は容赦のない人なんだぜ。","ENG":"Heh, I feel sorry for ya. You see, our boss is a ruthless man.","TWN":"呵呵，講不聽欸，我告訴你，我們老大非常不好惹喔！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"차라리 지금이라도 집에 연락해서 돈을 달라고 하는 건 어때? 우리 형님은 복수는 참아도 돈이라면 사족을 못 쓰시거든.","JPN":"今からでも家族に連絡して金を用意してもらったらどうだ？　兄貴は金で許してくれるぞ。","ENG":"How about you call home and get us some money? Boss might not need to get revenge if money's involved.","TWN":"還是直接打到她家裡要錢吧？我們老大可是視錢如命欸，連殺父仇人都沒有比錢重要。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그건 별로 좋은 생각은 아닌 것 같소.","JPN":"それはあまり良い考えではなさそうです。","ENG":"I do not think that will be a good idea.","TWN":"這似乎不是一個好主意。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인이 집으로 연락하면 돈이 아니라 그대들의 목을 베러 살수들이 찾아올 거요.","JPN":"自分が家族に連絡すると、お金ではなく貴殿らの首を切り落とす者を寄こすでしょう。","ENG":"My contacting home will not end with you getting money, but with a blade to sever your heads.","TWN":"如果打去在下家裡，你們恐怕不只要不到錢，他們還會派殺手來找你們。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"뭐라고…?! 그게 정말이야?! 설마 우리 사람을 잘못 건드린 건가?!","JPN":"なんだと……！？　それは本当か！？　まさか俺たち、とんでもねぇ人に手を出しちゃったのか！？","ENG":"What...?! You're not kidding?! Did we mess with the wrong person?!","TWN":"什麼…？真的假的？我們是不是惹錯人啦？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"이 바보야. 호들갑 떨지 마. 우릴 겁주려는 걸 수도 있잖아.","JPN":"このアホ、慌てるな。俺たちのことを脅かしてるのかもしれねえだろ？","ENG":"You idiot. Quit making a fuss. She could be bluffing.","TWN":"你這蠢蛋，瞧你嚇的！說不定她只是在嚇唬我們？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"그치만 진짜면 어떡해?","JPN":"でも、マジならどうすんだよ。","ENG":"But what if she's telling the truth?","TWN":"但萬一真的呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"서, 설마… 마피아 보스의 딸 같은 걸 잘못 건드린 건 아니겠지?","JPN":"ま、まさか……マフィアのボスの娘に手を出しちゃったんじゃないだろな？","ENG":"S-she's not... like the daughter of a mob boss or anything, right?","TWN":"怎，怎麼可能…她總不可能是黑手黨老大的女兒吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"그럼 어떻게 하든 우린 죽은 목숨이잖아! 난 아직 죽고 싶지 않아!","JPN":"それじゃあ、どう足掻いても俺らは死ぬだろ！　俺はまだ死にたくないよ！","ENG":"What if she is?! We'll be sleeping with the fishes! I don't wanna die!","TWN":"總之不管怎樣我們都是死路一條，可我還不想死啊！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"날 잡으라고 지시한 그대들의 두목은 어디에 있소?","JPN":"自分のことを捕まえるように指示した貴殿らのお頭はどこにいるのですか？","ENG":"Where is your head that ordered you to kidnap me?","TWN":"那位指使你們把在下抓來這裡的老大，現在在哪裡？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"히익?! 밧줄을 힘으로 끊었어?!","JPN":"ひいっ！？　ロープを力づくでちぎった！？","ENG":"Eek! She broke the rope with her bare arms!","TWN":"欸欸？！你把繩子掙斷啦？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"말도 안 돼! 네… 네가 너무 느슨하게 묶은 거 아냐?!","JPN":"ウソだろ！　お……お前、緩く結んだんじゃねえの！？","ENG":"No way! Y-you must've tied it loosely!","TWN":"這怎麼可能！是…是剛才綁得不夠緊嗎？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"이, 이, 일단 막아! 쟤가 여기서 빠져나가기라도 하면 두목이 우릴 두들겨 팰 거라고!","JPN":"と、と、とりあえず止めろ！　あいつがここから出たら、親分に殴られる！","ENG":"A-anyway! G-get her! If she escapes, boss is gonna pummel us to death!","TWN":"快，快，快抓住她！要是被她給逃走，我們會死很慘的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};